import threading, heapq, time
from exchange_service import MatchingEngine, ThreadSafeMatchingEngine
from models import Side, OrderBook

orig_peek = OrderBook._peek_active
def slow_peek(self, heap):
    while True:
        if not (heap and not heap[0].order.is_active):
            break
        time.sleep(0)
        heapq.heappop(heap)
    return heap[0].order if heap else None

def run(engine_cls):
    OrderBook._peek_active = slow_peek
    try:
        errs = []
        for trial in range(30):
            engine = engine_cls(["AAPL"])
            # Rest many SELLs on _asks, cancel most so they become DEAD tops that
            # _peek_active must purge. Both snapshot (best_ask) and submit (match
            # against asks) traverse and pop from _asks -> shared mutation.
            ids = []
            for i in range(400):
                o,_ = engine.submit_order("AAPL", Side.SELL, price_cents=1000+i%3, quantity=10)
                ids.append(o.order_id)
            for oid in ids:
                engine.cancel_order(oid)   # all dead now
            stop = threading.Event()
            def poller():
                while not stop.is_set():
                    try:
                        engine.snapshot("AAPL")
                    except Exception as e:
                        errs.append(repr(e)); return
            def submitter():
                # crossing buys: match() walks _asks popping the dead tops
                for i in range(50):
                    try:
                        engine.submit_order("AAPL", Side.BUY, price_cents=2000, quantity=10)
                    except Exception as e:
                        errs.append(repr(e)); return
            ps=[threading.Thread(target=poller) for _ in range(6)]
            sub=threading.Thread(target=submitter)
            for p in ps: p.start()
            sub.start(); sub.join(); stop.set()
            for p in ps: p.join()
            if errs: break
        return errs
    finally:
        OrderBook._peek_active = orig_peek

u = run(MatchingEngine)
print("UNLOCKED:", len(u), u[:2])
l = run(ThreadSafeMatchingEngine)
print("LOCKED:  ", len(l), l[:2])
